void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vUv = 0.5 + (vUv-0.5)*0.98;
    vec2 d = uTexSize.zw*4;
    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

vec4 noise = texture3D(sampler_noisevol_hq, ((vUv.xyy+vec3(lum(dx),lum(dy),0)*0.5)*uTexSize.xyy*texsize_noisevol_hq.zww).xyz*vec3(1,1,0)*0.05
